import { useState, useEffect, useRef, useCallback } from "react";

// ── Brand ──────────────────────────────────────────────────────
const BRAND = {
  dark:   "#1a5fa8",
  mid:    "#2281cc",
  light:  "#4db8e8",
  pale:   "#a8d8f0",
  white:  "#ffffff",
  bg:     "#f0f6fc",
};

// ── Simulation constants ───────────────────────────────────────
const GRAIN_CAP   = 23000;
const SALT_DOSE   = 7;
const BRINE_GPM   = 0.5;
const RESERVE     = 0.15;
const IRON_F      = 4;
const SALT_MAX    = 80;
const IMG_RESINREVIVE = "data:image/png;base64,";
const IMG_MORTON      = "data:image/webp;base64,";
const IMG_IRONOUT     = "data:image/jpeg;base64,";
const USABLE      = Math.round(GRAIN_CAP * (1 - RESERVE));
const DEG_PER_SEC = 18;
const DEG_PER_POS = 72;

const CY = [
  { id:0, name:"Service",          short:"SVC", color:"#00ff88", dim:"#002b14" },
  { id:1, name:"Brine Tank Fill",  short:"BTF", color:"#00ddff", dim:"#001c2b" },
  { id:2, name:"Brine/Slow Rinse", short:"BSR", color:"#4499ff", dim:"#001133" },
  { id:3, name:"Backwash",         short:"BW",  color:"#ffaa00", dim:"#2b1c00" },
  { id:4, name:"Fast Rinse",       short:"FR",  color:"#cc44ff", dim:"#1b0030" },
];

// ── Helpers ────────────────────────────────────────────────────
const p2  = n => String(Math.floor(Math.abs(n))).padStart(2,"0");
const mms = s => `${p2(s/60)}:${p2(s%60)}`;
const fN  = (n,d=0) => Number(Number(n).toFixed(d)).toLocaleString();
const PCB_BG   = "#060a10";
const PCB_BR   = "#2a4a6a";
const PCB_CARD = "#0c1220";
const mo  = (col="#ffffff",sz=11,x={}) => ({color:col,fontSize:sz,fontWeight:"bold",fontFamily:"'Courier New',monospace",...x});
const cd  = x => ({background:PCB_CARD,border:`1px solid ${PCB_BR}`,borderRadius:8,...x});
const bb  = (col,x={}) => ({background:`${col}18`,border:`1px solid ${col}44`,color:col,
  borderRadius:4,padding:"6px 12px",cursor:"pointer",fontSize:11,
  fontFamily:"'Courier New',monospace",transition:"all .18s",...x});

// ─────────────────────────────────────────────────────────────
//  SHARED SIMULATION STATE (ref-based, passed down as prop)
// ─────────────────────────────────────────────────────────────
function useSimEngine() {
  // Settings
  const [hardness,   setHardness  ] = useState(7);
  const [iron,       setIron      ] = useState(0);
  const [manganese,  setManganese ] = useState(0);
  const [bwMin,      setBwMin     ] = useState(10);
  const [bsrMin,     setBsrMin    ] = useState(60);
  const [frMin,      setFrMin     ] = useState(10);
  const [rfMin,      setRfMin     ] = useState(12);
  const [mode,       setMode      ] = useState("meter");
  const [regenHour,  setRegenHour ] = useState(2);
  const [dayOvr,     setDayOvr    ] = useState(14);
  const [flowRate,   setFlowRate  ] = useState(3.0);
  const [saltLbs,    setSaltLbs   ] = useState(40);
  const [speed,      setSpeed     ] = useState(120);
  const [bypass,     setBypass    ] = useState(false);
  const [vacation,   setVacation  ] = useState(false);
  const [running,    setRunning   ] = useState(false);
  const [fullBrine,  setFullBrine ] = useState(false); // false=partial (efficient), true=full dose

  // Live sim state in refs
  const S = useRef({
    discAngle:0, motorOn:false, advancing:false, targetAngle:0, returning:false,
    currentCycle:0, cycleElapsed:0, regenActive:false, pending:false,
    totalGal:0, galSinceRegen:0, regenStartGal:0, peakFlow:0, regenCnt:0, lastRegen:null,
    // Live fluctuating flow (±5% noise, slow drift, burst events)
    liveFlow: 3.0,
    flowPhase: 0,        // sine wave phase for slow drift
    flowBurst: 0,        // burst timer for sudden usage spikes
    // Pressure simulation
    presPsi:  62, postPsi: 58,
    // presHistory stores {t, pre, post} objects — up to 43200 samples (1 month @2s each)
    presHistory: [],
    postHistory: Array(48).fill(58),  // legacy (unused after refactor)
    // Flow history — same structure: {t, flow}
    flowHistory: [],
    // 1-minute data log — {t, pre, post, flow, note?}
    dataLog: [],
    logTimer: 0,
    usageHistory: Array(7).fill(0),   // daily gal last 7 days
    todayGal: 0,
    // Failure flags
    faultMotorStall:  false,
    faultLowPressure: false,
    faultFlowMeter:   false,
    faultLowSalt:     false,
    faultHighDiff:    false,
    motorStallTimer:  0,
    // For motor stall detection
    lastAngleCheck: 0, lastAngleVal: 0,
  });

  const [tick, setTick] = useState(0);
  const [now,  setNow ] = useState(new Date());
  const [log,  setLog ] = useState([]);
  const [alerts, setAlerts] = useState([]);

  const push = useCallback((t,m) =>
    setAlerts(p=>[{t,m,ts:new Date().toLocaleTimeString()},...p.slice(0,99)]),[]);

  const cfg = useRef({hardness,iron,manganese,bwMin,bsrMin,frMin,rfMin,mode,regenHour,
    dayOvr,flowRate,bypass,vacation,speed,saltLbs,fullBrine});
  useEffect(()=>{ cfg.current={hardness,iron,manganese,bwMin,bsrMin,frMin,rfMin,mode,
    regenHour,dayOvr,flowRate,bypass,vacation,speed,saltLbs,fullBrine}; });

  const effH    = Math.max(0.5, hardness + iron*IRON_F + manganese*2);
  const galTrig = Math.floor(USABLE / effH);
  const s       = S.current;
  const grainUsed = Math.min(USABLE, s.galSinceRegen * effH);
  const grainRem  = Math.max(0, USABLE - grainUsed);
  const galRem    = Math.max(0, galTrig - s.galSinceRegen);
  const capPct    = (grainRem / USABLE) * 100;
  const trigPct   = Math.min(100, (s.galSinceRegen / galTrig) * 100);
  // New cycle order: 1=Brine Tank Fill(rfMin), 2=Brine/Slow Rinse(bsrMin), 3=Backwash(bwMin), 4=Fast Rinse(frMin)
  const brineFrac = Math.max(0.1, Math.min(1, s.galSinceRegen / Math.max(1, galTrig))); // partial dose ratio
  const durSec    = {
    1: Math.round(rfMin  * (fullBrine ? 1 : brineFrac)) * 60,  // Brine Tank Fill — scaled if partial
    2: Math.round(bsrMin * (fullBrine ? 1 : brineFrac)) * 60,  // Brine/Slow Rinse — scaled if partial
    3: bwMin  * 60,                                              // Backwash — always full
    4: frMin  * 60,                                              // Fast Rinse — always full
  };
  const cycleRem  = s.currentCycle>0&&!s.advancing ? Math.max(0,durSec[s.currentCycle]-s.cycleElapsed) : null;
  const totalRgn  = bwMin+bsrMin+frMin+rfMin;
  const presDiff  = Math.abs(s.presPsi - s.postPsi);

  // System health
  const anyFault = s.faultMotorStall||s.faultLowPressure||s.faultFlowMeter||s.faultHighDiff;
  const needsService = s.faultLowSalt || trigPct>85 || (saltLbs/SALT_MAX<0.25);
  const systemStatus = anyFault?"failure":needsService?"service":"ok";

  useEffect(()=>{
    if(!running) return;
    let lastMs = Date.now();
    const id = setInterval(()=>{
      const t2 = Date.now();
      const dt_r = Math.min((t2-lastMs)/1000, 0.1);
      lastMs = t2;
      const s = S.current, c2 = cfg.current;
      const dt_s = dt_r * c2.speed;
      setNow(new Date());

      // Motor rotation
      if(s.motorOn){
        s.discAngle += DEG_PER_SEC * dt_r;
        s.motorStallTimer = 0;
        if(s.discAngle >= s.targetAngle){
          s.discAngle = s.targetAngle % 360;
          s.motorOn = false; s.advancing = false;
          s.faultMotorStall = false;
          if(s.returning){
            const cnt = s.regenCnt+1;
            // Scale salt by how full the resin was when regen triggered
            const effHnow = Math.max(0.5, c2.hardness + c2.iron*IRON_F + c2.manganese*2);
            const galTrigNow = Math.floor(USABLE / effHnow);
            const bf = c2.fullBrine ? 1 : Math.max(0.1, Math.min(1, (s.regenStartGal||galTrigNow) / Math.max(1, galTrigNow)));
            const saltUsed = Math.round(SALT_DOSE * bf * 10) / 10;
            s.returning=false; s.currentCycle=0; s.regenActive=false;
            s.pending=false; s.galSinceRegen=0; s.cycleElapsed=0; s.regenStartGal=0;
            s.regenCnt=cnt; s.lastRegen=new Date();
            const ns = Math.max(0, c2.saltLbs - saltUsed);
            setSaltLbs(ns); cfg.current.saltLbs=ns;
            setLog(p=>[{no:cnt, date:new Date().toLocaleDateString(),
              time:new Date().toLocaleTimeString(), gal:Math.round(s.totalGal),
              saltUsed, partial:!c2.fullBrine},...p.slice(0,49)]);
            push("ok",`✓ Regen #${cnt} complete — ${c2.fullBrine?"Full":"Partial"} brine · ${saltUsed} lbs salt`);
            if(ns/SALT_MAX<0.25) push("warn","⚠ Salt level low — refill brine tank");
          } else {
            const nc = Math.round(s.targetAngle/72)%5;
            s.currentCycle=nc; s.cycleElapsed=0;
          }
        }
      } else if(s.regenActive && s.currentCycle > 0 && !s.returning) {
        // Motor stall detection: motor should be on during advancing
        // only flag if we were supposed to be moving but aren't
      }

      // Cycle timer — new order: 1=BTF(rfMin), 2=BSR(bsrMin), 3=BW(bwMin), 4=FR(frMin)
      if(!s.motorOn&&s.regenActive&&s.currentCycle>0&&!s.returning){
        const bf = c2.fullBrine ? 1 : Math.max(0.1,Math.min(1,s.regenStartGal/Math.max(1,Math.floor(USABLE/Math.max(0.5,c2.hardness+c2.iron*IRON_F+c2.manganese*2)))));
        const durMap = {
          1: Math.round(c2.rfMin  * (c2.fullBrine?1:bf)) * 60,
          2: Math.round(c2.bsrMin * (c2.fullBrine?1:bf)) * 60,
          3: c2.bwMin  * 60,
          4: c2.frMin  * 60,
        };
        const dur = durMap[s.currentCycle] || 60;
        s.cycleElapsed+=dt_s;
        if(s.cycleElapsed>=dur){
          s.cycleElapsed=0;
          if(s.currentCycle<4){
            s.targetAngle=(s.currentCycle+1)*72; s.motorOn=true; s.advancing=true;
          } else {
            s.targetAngle=360; s.motorOn=true; s.advancing=true;
            s.returning=true; s.currentCycle=0;
          }
        }
      }

      // Pending → start regen
      if(s.pending&&!s.regenActive&&!s.motorOn&&s.currentCycle===0&&!s.returning){
        const h=new Date().getHours();
        const go=c2.mode==="meter"||c2.mode==="both"||(c2.mode==="time"&&h===c2.regenHour);
        if(go){
          s.regenStartGal = s.galSinceRegen; // capture gallons used — determines brine fraction
          s.regenActive=true; s.targetAngle=72; s.motorOn=true; s.advancing=true;
          push("warn","Regeneration cycle started");
          // Seed pressure history if empty
          if(s.presHistory.length===0){
            const now_ms=Date.now();
            s.presHistory=Array.from({length:30},(_,i)=>({
              t:now_ms-(30-i)*2000, pre:62+(Math.random()-0.5)*2, post:58+(Math.random()-0.5)*2
            }));
          }
        }
      }

      // ── Dynamic flow fluctuation ─────────────────────────────
      // Base = user-set flowRate. Live flow drifts with a slow sine wave
      // (simulates demand cycles) plus high-freq noise (pipe turbulence)
      // plus occasional "burst" events (toilet flush, shower starting).
      if(c2.flowRate > 0 && !c2.bypass && !c2.vacation && !s.regenActive) {
        // Advance slow-drift phase (real-time, not sim-speed)
        s.flowPhase += dt_r * 0.12;           // ~52s per full cycle
        // Slow sinusoidal drift: ±3% of base
        const drift  = Math.sin(s.flowPhase) * c2.flowRate * 0.03;
        // High-freq noise: ±2%
        const noise  = (Math.random() - 0.5) * c2.flowRate * 0.02;
        // Burst events: ~5% chance per second a "surge" starts
        if(s.flowBurst <= 0 && Math.random() < dt_r * 0.05) {
          s.flowBurst = 0.8 + Math.random() * 1.4;  // burst lasts 0.8–2.2 real-s
        }
        const burstAmt = s.flowBurst > 0 ? c2.flowRate * 0.04 : 0;
        s.flowBurst   = Math.max(0, s.flowBurst - dt_r);
        // Compose: clamp to [base×0.92, base×1.08]  (±8% max swing)
        const base = c2.flowRate;
        s.liveFlow = Math.max(base * 0.92, Math.min(base * 1.08, base + drift + noise + burstAmt));
      } else if(c2.flowRate === 0 || c2.bypass || c2.vacation || s.regenActive) {
        s.liveFlow = 0;
      }

      // Gallon counting (use liveFlow for realistic accumulation)
      const flowing=!c2.bypass&&!c2.vacation&&c2.flowRate>0;
      if(flowing&&!s.regenActive&&!s.pending){
        const gal=(s.liveFlow*dt_s)/60;
        s.totalGal+=gal; s.galSinceRegen+=gal; s.todayGal+=gal;
        s.peakFlow=Math.max(s.peakFlow,s.liveFlow);
        if(s.galSinceRegen>=galTrig){
          s.pending=true;
          push("warn",`Volume trigger: ${Math.round(s.galSinceRegen).toLocaleString()} gal — regen queued`);
        }
        if(c2.dayOvr>0&&s.lastRegen&&(Date.now()-s.lastRegen.getTime())>=c2.dayOvr*86400000){
          s.pending=true; push("warn","Day override — regen queued");
        }
      }
      if(c2.bypass&&!c2.vacation&&c2.flowRate>0) s.totalGal+=(c2.flowRate*dt_s)/60;

      // Pressure simulation (tracks liveFlow so PSI fluctuates with flow)
      const targetPre  = c2.bypass?62:s.regenActive?45:58+s.liveFlow*0.4;
      const targetPost = c2.bypass?61:s.regenActive?42:(58+s.liveFlow*0.4)-(presDiff*0.9);
      s.presPsi  += (targetPre  - s.presPsi)*0.04;
      s.postPsi  += (targetPost - s.postPsi)*0.04;
      s.presPsi  += (Math.random()-0.5)*0.3;
      s.postPsi  += (Math.random()-0.5)*0.3;

      // Fault detection
      s.faultLowPressure = s.presPsi < 20;
      s.faultHighDiff    = Math.abs(s.presPsi-s.postPsi) > 15;
      s.faultLowSalt     = saltLbs/SALT_MAX < 0.15;
      if(s.faultLowPressure) push("error","⚠ Low inlet water pressure detected");
      if(s.faultHighDiff)    push("warn","⚠ High pressure differential — check filter");

      // Pressure history — 1 real-time sample per 2 seconds, timestamped
      s.presTimer = (s.presTimer||0) + dt_r;
      if(s.presTimer >= 2.0){
        s.presTimer = 0;
        const now_ms = Date.now();
        const entry = { t: now_ms, pre: Math.round(s.presPsi*10)/10, post: Math.round(s.postPsi*10)/10 };
        s.presHistory = [...s.presHistory, entry].slice(-43200); // keep up to 1 month of 2s samples
        // Flow history — same 2s sample rate
        s.flowHistory = [...(s.flowHistory||[]), { t: now_ms, flow: Math.round(s.liveFlow*100)/100 }].slice(-43200);
      }

      // 1-minute data log (all parameters) + exception logging
      s.logTimer = (s.logTimer||0) + dt_r;
      if(s.logTimer >= 60){
        s.logTimer = 0;
        const ts = Date.now();
        const entry = {
          t: ts,
          ts: new Date(ts).toLocaleString(),
          pre:  Math.round(s.presPsi*10)/10,
          post: Math.round(s.postPsi*10)/10,
          flow: Math.round(s.liveFlow*100)/100,
          dp:   Math.round(Math.abs(s.presPsi-s.postPsi)*10)/10,
          cycle: s.regenActive ? CY[s.currentCycle]?.name||"Regen" : "Service",
        };
        // Tag exceptions
        const notes = [];
        if(s.presPsi < 25) notes.push("⚠ Low inlet pressure");
        if(Math.abs(s.presPsi-s.postPsi) > 15) notes.push("⚠ High ΔP");
        if(s.liveFlow > c2.flowRate*1.15) notes.push("⚡ Flow spike");
        if(s.liveFlow > 0 && s.liveFlow < c2.flowRate*0.5 && c2.flowRate>0) notes.push("↓ Low flow");
        if(notes.length) entry.note = notes.join(", ");
        s.dataLog = [...(s.dataLog||[]), entry].slice(-44640); // 31 days × 1440 min/day
      }

      setTick(n=>n+1);
    },30);
    return()=>clearInterval(id);
  },[running]);

  // Controls
  const manualRegen=()=>{
    if(s.regenActive||s.pending) return;
    S.current.pending=true; push("info","Manual regen initiated"); setTick(n=>n+1);
  };
  const advanceCycle=()=>{
    if(!s.regenActive||s.motorOn||s.currentCycle===0||s.returning) return;
    const next=Math.min(s.currentCycle+1,4);
    S.current.targetAngle=next*72; S.current.motorOn=true;
    S.current.advancing=true; S.current.cycleElapsed=0; setTick(n=>n+1);
  };
  const forceDisc=i=>{
    if(s.motorOn) return;
    S.current.discAngle=i*72; S.current.targetAngle=i*72;
    S.current.currentCycle=i; S.current.cycleElapsed=0;
    S.current.advancing=false; S.current.returning=false;
    if(i===0){S.current.regenActive=false;S.current.pending=false;}
    else S.current.regenActive=true;
    setTick(n=>n+1);
  };
  const resetAll=()=>{
    Object.assign(S.current,{discAngle:0,motorOn:false,advancing:false,targetAngle:0,
      returning:false,currentCycle:0,cycleElapsed:0,regenActive:false,pending:false,
      totalGal:0,galSinceRegen:0,regenStartGal:0,peakFlow:0,regenCnt:0,lastRegen:null,todayGal:0,
      liveFlow:0,flowPhase:0,flowBurst:0,
      flowHistory:[],dataLog:[],logTimer:0,
      faultMotorStall:false,faultLowPressure:false,faultFlowMeter:false,
      faultLowSalt:false,faultHighDiff:false,presPsi:62,postPsi:58});
    setRunning(false);setSaltLbs(40);setLog([]);setAlerts([]);setTick(n=>n+1);
  };
  const injectGal=v=>{
    S.current.galSinceRegen=Math.max(0,Math.min(galTrig,v));
    S.current.totalGal=Math.max(S.current.totalGal,S.current.galSinceRegen);
    setTick(n=>n+1);
  };

  return {
    // settings
    hardness,setHardness,iron,setIron,manganese,setManganese,bwMin,setBwMin,bsrMin,setBsrMin,
    frMin,setFrMin,rfMin,setRfMin,mode,setMode,regenHour,setRegenHour,
    dayOvr,setDayOvr,flowRate,setFlowRate,saltLbs,setSaltLbs,speed,setSpeed,
    bypass,setBypass,vacation,setVacation,running,setRunning,fullBrine,setFullBrine,
    // derived
    s,effH,galTrig,grainUsed,grainRem,galRem,capPct,trigPct,brineFrac,durSec,cycleRem,
    totalRgn,presDiff,anyFault,needsService,systemStatus,
    // display
    tick,now,log,alerts,setAlerts,
    // actions
    manualRegen,advanceCycle,forceDisc,resetAll,injectGal,push,
    // raw refs (for ScreenHome scheduleRegenTonight)
    S, setTick,
  };
}

// ─────────────────────────────────────────────────────────────
//  PCB COMPONENTS
// ─────────────────────────────────────────────────────────────
function LED({ on, col="#00ff88", pulse=false }) {
  return <div style={{width:10,height:10,borderRadius:"50%",flexShrink:0,
    background:on?col:"#0c1018",border:`1px solid ${on?col+"77":"#1a2535"}`,
    boxShadow:on?`0 0 7px ${col},0 0 14px ${col}44`:undefined,
    transition:"all .25s",animation:on&&pulse?"ws-pulse 1.3s ease infinite":undefined}}/>;
}
function Gauge({ label, val, max, unit, col, d=0 }) {
  const p = Math.max(0,Math.min(1,val/max));
  const fill = p<0.1?"#ff3333":p<0.25?"#ffaa00":col;
  return (
    <div style={{marginBottom:8}}>
      <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
        <span style={mo("#ffffff",10.5)}>{label}</span>
        <span style={mo("#ffffff",10.5)}>{fN(val,d)} / {fN(max,d)} {unit}</span>
      </div>
      <div style={{background:"#070a0f",borderRadius:3,height:7,overflow:"hidden",border:"1px solid #141d28"}}>
        <div style={{width:`${p*100}%`,height:"100%",background:fill,
          transition:"width .5s,background .5s",boxShadow:`0 0 8px ${fill}55`}}/>
      </div>
    </div>
  );
}
function Stat({ label, val, unit="", col="#ffffff", big=false }) {
  return (
    <div style={{background:"#0b0f1a",border:"1px solid #1a2535",borderRadius:6,
      padding:"8px 10px",textAlign:"center"}}>
      <div style={{fontSize:8.5,color:"#e0eeff",marginBottom:2,textTransform:"uppercase",
        letterSpacing:1,fontFamily:"monospace"}}>{label}</div>
      <div style={{fontSize:big?21:15,fontWeight:"bold",fontFamily:"'Courier New',monospace",
        color:col,lineHeight:1,textShadow:big?`0 0 10px ${col}44`:undefined}}>{val}</div>
      {unit&&<div style={{fontSize:8,color:"#223344",marginTop:2}}>{unit}</div>}
    </div>
  );
}
function DiscSVG({ angle, cycle, motorOn, advancing, returning }) {
  const cx=115,cy=115,OR=82,IR=24,reedR=107;
  const step=2*Math.PI/5,θ0=-Math.PI/2;
  const segs=CY.map((c,i)=>{
    const a0=θ0+i*step,a1=a0+step,mid=a0+step/2;
    const path=[`M${cx+IR*Math.cos(a0)},${cy+IR*Math.sin(a0)}`,
      `L${cx+OR*Math.cos(a0)},${cy+OR*Math.sin(a0)}`,
      `A${OR},${OR} 0 0,1 ${cx+OR*Math.cos(a1)},${cy+OR*Math.sin(a1)}`,
      `L${cx+IR*Math.cos(a1)},${cy+IR*Math.sin(a1)}`,
      `A${IR},${IR} 0 0,0 ${cx+IR*Math.cos(a0)},${cy+IR*Math.sin(a0)}Z`].join(" ");
    return {...c,path,lx:cx+(OR+IR)/2*Math.cos(mid),ly:cy+(OR+IR)/2*Math.sin(mid)};
  });
  const magX=cx+(OR-9)*Math.cos(θ0),magY=cy+(OR-9)*Math.sin(θ0);
  const reeds=CY.map((_,i)=>{
    const ang=θ0+i*step;
    return{x:cx+reedR*Math.cos(ang),y:cy+reedR*Math.sin(ang),
      active:(!advancing&&!returning&&cycle===i)||(returning&&i===0),col:CY[i].color};
  });
  return (
    <svg width={230} height={230} viewBox="0 0 230 230" style={{overflow:"visible",display:"block"}}>
      <defs><radialGradient id="dg2" cx="50%" cy="50%">
        <stop offset="0%" stopColor="#0e1525"/><stop offset="100%" stopColor="#060910"/>
      </radialGradient></defs>
      <circle cx={cx} cy={cy} r={reedR+22} fill="url(#dg2)" stroke="#192030" strokeWidth="2"/>
      <circle cx={cx} cy={cy} r={reedR+18} fill="none" stroke="#0e1620" strokeWidth="5"/>
      {Array.from({length:40},(_,i)=>{
        const a=θ0+(i/40)*2*Math.PI,r1=reedR+18,r2=i%8===0?reedR+12:reedR+16;
        return <line key={i} x1={cx+r1*Math.cos(a)} y1={cy+r1*Math.sin(a)}
          x2={cx+r2*Math.cos(a)} y2={cy+r2*Math.sin(a)}
          stroke={i%8===0?"#e0eeff":"#131d28"} strokeWidth={i%8===0?1.5:.7}/>;
      })}
      {reeds.map((r,i)=>(
        <g key={i}>
          <circle cx={r.x} cy={r.y} r={11} fill={r.active?"#ffcc00":"#0b0d18"}
            stroke={r.active?"#ff9900":"#192030"} strokeWidth="1.5"
            style={{transition:"all .15s",filter:r.active?"drop-shadow(0 0 9px #ffcc00)":undefined}}/>
          <text x={r.x} y={r.y} textAnchor="middle" dominantBaseline="middle"
            fontSize="6" fontFamily="monospace" fill={r.active?"#331100":"#253040"}>S{i+1}</text>
        </g>
      ))}
      <g style={{transform:`rotate(${angle%360}deg)`,transformOrigin:`${cx}px ${cy}px`}}>
        {segs.map((s,i)=>{
          const glow=!advancing&&!returning&&cycle===i;
          return (<g key={i}>
            <path d={s.path} fill={s.color} stroke="#04070d" strokeWidth="1.5" opacity={0.9}
              style={{filter:glow?`drop-shadow(0 0 12px ${s.color}cc)`:`drop-shadow(0 0 2px ${s.color}33)`}}/>
            <text x={s.lx} y={s.ly} textAnchor="middle" dominantBaseline="middle"
              fontSize="7.5" fontFamily="monospace" fontWeight="bold"
              fill={glow?"#000":"#00000099"} style={{pointerEvents:"none"}}>{s.short}</text>
          </g>);
        })}
        <circle cx={magX} cy={magY} r={5.5} fill="#ff2200" stroke="#ff6600" strokeWidth="1.5"
          style={{filter:"drop-shadow(0 0 7px #ff2200aa)"}}/>
        <text x={magX} y={magY} textAnchor="middle" dominantBaseline="middle"
          fontSize="5" fontFamily="monospace" fill="#fff" style={{pointerEvents:"none"}}>M</text>
      </g>
      <circle cx={cx} cy={cy} r={IR+3} fill="#070a12" stroke="#192030" strokeWidth="2"/>
      <circle cx={cx} cy={cy} r={IR}   fill="#050810" stroke="#0e1620" strokeWidth="1"/>
      <circle cx={cx} cy={cy} r={5}    fill={motorOn?"#ffaa00":"#192030"}
        stroke={motorOn?"#ff8800":"#0e1620"} strokeWidth="1.5"
        style={{transition:"fill .3s",filter:motorOn?"drop-shadow(0 0 9px #ffaa00)":undefined}}/>
      <polygon points={`${cx},${cy-OR+4} ${cx-7},${cy-OR-16} ${cx+7},${cy-OR-16}`} fill="#c8d8f0" opacity={0.75}/>
      <line x1={cx-7} y1={cy-OR-16} x2={cx+7} y2={cy-OR-16} stroke="#3a77cc" strokeWidth="1.5"/>
    </svg>
  );
}

