// Pressure arc component
function PressureArc({ psi, max=100, label, color }) {
  const pct = Math.min(1, psi/max);
  const r = 38, cx=50, cy=55;
  const startAngle = -210 * Math.PI/180;
  const endAngle   = 30  * Math.PI/180;
  const totalArc   = endAngle - startAngle;
  const fillAngle  = startAngle + totalArc * pct;
  const x1=cx+r*Math.cos(startAngle), y1=cy+r*Math.sin(startAngle);
  const x2=cx+r*Math.cos(fillAngle),  y2=cy+r*Math.sin(fillAngle);
  const x3=cx+r*Math.cos(endAngle),   y3=cy+r*Math.sin(endAngle);
  const large = totalArc * pct > Math.PI ? 1 : 0;
  const large2 = totalArc * (1-pct) > Math.PI ? 1 : 0;
  return (
    <svg viewBox="0 0 100 80" style={{width:100,height:80}}>
      <path d={`M${x1},${y1} A${r},${r} 0 ${totalArc>Math.PI?1:0},1 ${x3},${y3}`}
        fill="none" stroke="#e8f4fb" strokeWidth="6" strokeLinecap="round"/>
      {pct>0&&<path d={`M${x1},${y1} A${r},${r} 0 ${large},1 ${x2},${y2}`}
        fill="none" stroke={color} strokeWidth="6" strokeLinecap="round"
        style={{filter:`drop-shadow(0 0 4px ${color}88)`}}/>}
      <text x={cx} y={cy-4} textAnchor="middle" fontSize="14" fontWeight="bold"
        fill={color} fontFamily="'DM Sans',sans-serif">{Math.round(psi)}</text>
      <text x={cx} y={cy+9} textAnchor="middle" fontSize="7" fill="#7a9bb5"
        fontFamily="sans-serif">PSI</text>
      <text x={cx} y={cy+20} textAnchor="middle" fontSize="7" fill="#4a6a80"
        fontFamily="sans-serif">{label}</text>
    </svg>
  );
}

// Mini sparkline
function Sparkline({ data, color, height=32 }) {
  const min = Math.min(...data);
  const max = Math.max(...data) || 1;
  const w = 120, h = height;
  const pts = data.map((v,i)=>{
    const x = (i/(data.length-1))*w;
    const y = h - ((v-min)/(max-min||1))*h*0.8 - h*0.1;
    return `${x},${y}`;
  }).join(" ");
  const area = `0,${h} ${pts} ${w},${h}`;
  return (
    <svg viewBox={`0 0 ${w} ${h}`} style={{width:"100%",height}}>
      <defs><linearGradient id="spGrad" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stopColor={color} stopOpacity="0.3"/>
        <stop offset="100%" stopColor={color} stopOpacity="0.02"/>
      </linearGradient></defs>
      <polygon points={area} fill="url(#spGrad)"/>
      <polyline points={pts} fill="none" stroke={color} strokeWidth="1.5" strokeLinejoin="round"/>
    </svg>
  );
}

